133â†’/**
134â†’ * Scans a directory recursively for CLI tool files
135â†’ * 
136â†’ * @param dir - Directory to scan
137â†’ * @param pattern - File pattern to match (default: *-cli.ts)
138â†’ * @returns Array of file paths matching the pattern
139â†’ */
140â†’async function scanDirectory(dir: string, pattern: string = '*-cli.ts'): Promise<string[]> {
141â†’  const files: string[] = [];
142â†’  
143â†’  try {
144â†’    const entries = await readdir(dir, { withFileTypes: true });
145â†’    
146â†’    for (const entry of entries) {
147â†’      const fullPath = join(dir, entry.name);
148â†’      
149â†’      if (entry.isDirectory()) {
150â†’        // Recursively scan subdirectories
151â†’        const subFiles = await scanDirectory(fullPath, pattern);
152â†’        files.push(...subFiles);
153â†’      } else if (entry.isFile()) {
154â†’        // Check if file matches pattern
155â†’        if (entry.name.endsWith('-cli.ts') || entry.name.endsWith('-cli.js')) {
156â†’          files.push(fullPath);
157â†’        }
158â†’      }
159â†’    }
160â†’  } catch (error) {
161â†’    logger.warn(`Failed to scan directory ${dir}:`, error);
162â†’  }
163â†’  
164â†’  return files;
165â†’}
