167â†’/**
168â†’ * Loads a tool registration from a file
169â†’ * 
170â†’ * @param filePath - Path to the tool file
171â†’ * @returns Tool registration or null if failed
172â†’ */
173â†’async function loadToolFromFile(filePath: string): Promise<ToolRegistration | null> {
174â†’  try {
175â†’    // Convert file path to URL for dynamic import
176â†’    const fileUrl = pathToFileURL(filePath).href;
177â†’    
178â†’    // Dynamic import the module
179â†’    const module = await import(fileUrl);
180â†’    
181â†’    // Look for the tool registration export
182â†’    // We'll check for different possible export patterns
183â†’    let registration: ToolRegistration | null = null;
184â†’    
185â†’    // Pattern 1: Direct export of ToolRegistration
186â†’    if (module.default && typeof module.default === 'object' && 
187â†’        module.default.tool && module.default.handler) {
188â†’      registration = module.default;
189â†’    }
190â†’    
191â†’    // Pattern 2: Named export 'registration'
192â†’    if (!registration && module.registration && typeof module.registration === 'object' &&
193â†’        module.registration.tool && module.registration.handler) {
194â†’      registration = module.registration;
195â†’    }
196â†’    
197â†’    // Pattern 3: Separate tool and handler exports (legacy pattern)
198â†’    if (!registration) {
199â†’      // Try to find tool and handler exports
200â†’      const toolExport = Object.values(module).find(exp => 
201â†’        typeof exp === 'object' && exp !== null && 
202â†’        'name' in exp && 'description' in exp && 'inputSchema' in exp
203â†’      );
204â†’      
205â†’      const handlerExport = Object.values(module).find(exp => 
206â†’        typeof exp === 'function' && exp.name.includes('handle')
207â†’      );
208â†’      
209â†’      if (toolExport && handlerExport) {
210â†’        registration = {
211â†’          tool: toolExport as any,
212â†’          handler: handlerExport as any,
213â†’          schema: (toolExport as any).inputSchema
214â†’        };
215â†’      }
216â†’    }
217â†’    
218â†’    if (!registration) {
219â†’      logger.warn(`No valid tool registration found in ${filePath}`);
220â†’      return null;
221â†’    }
222â†’    
223â†’    // Validate the registration
224â†’    if (!registration.tool || !registration.tool.name || !registration.handler) {
225â†’      logger.warn(`Invalid tool registration in ${filePath}: missing tool name or handler`);
226â†’      return null;
227â†’    }
228â†’    
229â†’    return registration;
230â†’    
231â†’  } catch (error) {
232â†’    logger.warn(`Failed to load tool from ${filePath}:`, error);
233â†’    return null;
234â†’  }
235â†’}
