243â†’export async function loadTools(options: Partial<ToolScanOptions> = {}): Promise<ToolRegistry> {
244â†’  const opts = { ...DEFAULT_SCAN_OPTIONS, ...options };
245â†’  
246â†’  logger.info(`Scanning for CLI tools in ${opts.baseDir} with pattern ${opts.pattern}`);
247â†’  
248â†’  const registry: ToolRegistry = {
249â†’    tools: new Map(),
250â†’    handlers: new Map(),
251â†’    schemas: new Map()
